- In this context, a 'position' refers to a specific role or spot on the field, such as a forward, defender, or midfielder; 
- 'Total goals' refers to the sum of all goals scored by players in each position; 
- 'Total assists' refers to the sum of all assists made by players in each position.

sql:
SELECT player_id, SUM(yellow_cards) AS total_yellow_cards, SUM(red_cards) AS total_red_cards
FROM disciplinary_actions
GROUP BY player_id;

SELECT user_id, access_date, access_type
FROM user_logs
WHERE user_id = 0 AND access_date = '2023-05-02';

SELECT player_id, yellow_cards, suspension_games
FROM disciplinary_actions
WHERE yellow_cards > 0;
